import React, { useState, useEffect } from 'react';
import api from '../services/api';
import RevisarSolicitud from './RevisarSolicitud';

const SolicitudesPendientes = () => {
  const [solicitudes, setSolicitudes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [solicitudSeleccionada, setSolicitudSeleccionada] = useState(null);

  useEffect(() => {
    cargarSolicitudes();
  }, []);

  const cargarSolicitudes = async () => {
    try {
      setLoading(true);
      const response = await api.get('/solicitudes/pendientes');
      setSolicitudes(response.data.data || []);
    } catch (error) {
      console.error('Error cargando solicitudes:', error);
      setError('Error al cargar las solicitudes');
    } finally {
      setLoading(false);
    }
  };

  const handleSolicitudActualizada = () => {
    setSolicitudSeleccionada(null);
    cargarSolicitudes();
  };

  if (loading) {
    return (
      <div style={s.root}>
        <div style={s.header}>
          <div style={s.headerInner}>
            <div style={s.headerBadge}>COORDINADOR</div>
            <h1 style={s.headerTitle}>Solicitudes de Validación</h1>
            <p style={s.headerSub}>Revisa y gestiona las solicitudes enviadas por los instructores</p>
          </div>
        </div>
        <div style={s.body}>
          <div style={s.loadingState}>
            <div style={s.loadingSpinner} />
            <span style={s.loadingText}>Cargando solicitudes...</span>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div style={s.root}>
      {/* Header */}
      <div style={s.header}>
        <div style={s.headerInner}>
          <div style={s.headerBadge}>COORDINADOR</div>
          <h1 style={s.headerTitle}>Solicitudes de Validación</h1>
          <p style={s.headerSub}>Revisa y gestiona las solicitudes enviadas por los instructores</p>
        </div>
      </div>

      <div style={s.body}>

        {/* Contador */}
        {solicitudes.length > 0 && (
          <div style={s.statsRow}>
            <div style={s.statCard}>
              <span style={s.statNum}>{solicitudes.length}</span>
              <span style={s.statLabel}>Pendientes</span>
            </div>
          </div>
        )}

        {/* Alerta de error */}
        {error && (
          <div style={s.alertError}>
            <span style={s.alertDot} />
            {error}
          </div>
        )}

        {/* Estado vacío */}
        {solicitudes.length === 0 ? (
          <div style={s.emptyState}>
            <div style={s.emptyIcon}>
              <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round">
                <path d="M22 12h-4l-3 9L9 3l-3 9H2"/>
              </svg>
            </div>
            <p style={s.emptyTitle}>Sin solicitudes pendientes</p>
            <p style={s.emptyDesc}>Los instructores aún no han enviado solicitudes de validación</p>
          </div>
        ) : (
          <div style={s.grid}>
            {solicitudes.map((solicitud) => (
              <div key={solicitud._id} style={s.card}>

                {/* Card header */}
                <div style={s.cardTop}>
                  <div style={s.cardTopLeft}>
                    <span style={s.cardCode}>
                      {solicitud.oferta_id?.programa_formacion?.codigo}
                    </span>
                    <span style={s.badgePendiente}>Pendiente</span>
                  </div>
                  <div style={s.cardDate}>
                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ marginRight: 4 }}>
                      <rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/>
                    </svg>
                    {new Date(solicitud.fecha_solicitud).toLocaleDateString('es-CO')}
                  </div>
                </div>

                {/* Nombre programa */}
                <div style={s.cardBody}>
                  <h3 style={s.programaNombre}>
                    {solicitud.oferta_id?.programa_formacion?.nombre_programa}
                  </h3>

                  <div style={s.infoGrid}>
                    <div style={s.infoItem}>
                      <span style={s.infoLabel}>Instructor</span>
                      <span style={s.infoVal}>
                        {solicitud.instructor_id?.nombre} {solicitud.instructor_id?.apellido}
                      </span>
                    </div>
                    <div style={s.infoItem}>
                      <span style={s.infoLabel}>Correo</span>
                      <span style={{ ...s.infoVal, color: TEAL, fontSize: 13 }}>
                        {solicitud.instructor_id?.correoElectronico}
                      </span>
                    </div>
                  </div>

                  {solicitud.mensaje && (
                    <div style={s.mensajeBox}>
                      <span style={s.mensajeLabel}>Mensaje</span>
                      <p style={s.mensajeText}>{solicitud.mensaje}</p>
                    </div>
                  )}
                </div>

                {/* Footer */}
                <div style={s.cardFooter}>
                  <button
                    onClick={() => setSolicitudSeleccionada(solicitud._id)}
                    style={s.btn}
                  >
                    <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" style={{ marginRight: 7 }}>
                      <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>
                    </svg>
                    Revisar solicitud
                  </button>
                </div>

              </div>
            ))}
          </div>
        )}
      </div>

      {/* Modal */}
      {solicitudSeleccionada && (
        <div style={s.modalOverlay}>
          <div style={s.modalContent}>
            <RevisarSolicitud
              solicitudId={solicitudSeleccionada}
              onClose={() => setSolicitudSeleccionada(null)}
              onActualizar={handleSolicitudActualizada}
            />
          </div>
        </div>
      )}
    </div>
  );
};

/* ─── Tokens ─────────────────────────────────────────────────────────────── */
const TEAL     = '#0f6e56';
const TEAL_LIGHT = '#e1f5ee';
const TEAL_MID = '#1d9e75';
const INK      = '#1a1f2e';
const INK_SOFT = '#6b7280';
const BORDER   = '#e4e7ed';
const BG       = '#f5f6f8';
const WHITE    = '#ffffff';
const RED_BG   = '#fff0ee';
const RED_TXT  = '#993c1d';
const AMBER_BG = '#faeeda';
const AMBER_TXT = '#854f0b';

const s = {
  root: {
    fontFamily: "'DM Sans', 'Segoe UI', sans-serif",
    background: BG,
    minHeight: '100vh',
  },

  /* Header */
  header: {
    background: INK,
    padding: '40px 32px 36px',
  },
  headerInner: {
    maxWidth: 1100,
    margin: '0 auto',
  },
  headerBadge: {
    display: 'inline-block',
    background: TEAL_MID,
    color: WHITE,
    fontSize: 10,
    fontWeight: 700,
    letterSpacing: '0.12em',
    padding: '4px 10px',
    borderRadius: 4,
    marginBottom: 14,
  },
  headerTitle: {
    color: WHITE,
    fontSize: 26,
    fontWeight: 700,
    margin: '0 0 8px',
    letterSpacing: '-0.3px',
  },
  headerSub: {
    color: '#9aa3b5',
    fontSize: 14,
    margin: 0,
    lineHeight: 1.6,
  },

  /* Body */
  body: {
    maxWidth: 1100,
    margin: '0 auto',
    padding: '28px 24px 48px',
  },

  /* Stat */
  statsRow: {
    display: 'flex',
    gap: 16,
    marginBottom: 24,
  },
  statCard: {
    background: WHITE,
    border: `1px solid ${BORDER}`,
    borderRadius: 10,
    padding: '14px 22px',
    display: 'flex',
    flexDirection: 'column',
    gap: 2,
  },
  statNum: {
    fontSize: 26,
    fontWeight: 700,
    color: INK,
    lineHeight: 1,
  },
  statLabel: {
    fontSize: 12,
    fontWeight: 600,
    color: INK_SOFT,
    textTransform: 'uppercase',
    letterSpacing: '0.06em',
  },

  /* Alerta */
  alertError: {
    display: 'flex',
    alignItems: 'center',
    gap: 10,
    background: RED_BG,
    color: RED_TXT,
    border: `1px solid #f5c4b3`,
    borderRadius: 8,
    padding: '12px 16px',
    fontSize: 14,
    marginBottom: 20,
  },
  alertDot: {
    display: 'inline-block',
    width: 8,
    height: 8,
    borderRadius: '50%',
    background: RED_TXT,
    flexShrink: 0,
  },

  /* Empty */
  emptyState: {
    textAlign: 'center',
    padding: '60px 20px',
    background: WHITE,
    borderRadius: 12,
    border: `1px dashed ${BORDER}`,
  },
  emptyIcon: {
    width: 64,
    height: 64,
    borderRadius: '50%',
    background: TEAL_LIGHT,
    color: TEAL,
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    margin: '0 auto 16px',
  },
  emptyTitle: {
    fontSize: 17,
    fontWeight: 600,
    color: INK,
    margin: '0 0 6px',
  },
  emptyDesc: {
    fontSize: 14,
    color: INK_SOFT,
    margin: 0,
  },

  /* Loading */
  loadingState: {
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    gap: 16,
    padding: '80px 20px',
  },
  loadingSpinner: {
    width: 32,
    height: 32,
    border: `3px solid ${BORDER}`,
    borderTopColor: TEAL,
    borderRadius: '50%',
    animation: 'spin 0.7s linear infinite',
  },
  loadingText: {
    fontSize: 14,
    color: INK_SOFT,
  },

  /* Grid */
  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(340px, 1fr))',
    gap: 20,
  },

  /* Card */
  card: {
    background: WHITE,
    borderRadius: 12,
    border: `1px solid ${BORDER}`,
    overflow: 'hidden',
    display: 'flex',
    flexDirection: 'column',
  },
  cardTop: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    padding: '14px 18px',
    borderBottom: `1px solid ${BORDER}`,
    background: BG,
  },
  cardTopLeft: {
    display: 'flex',
    alignItems: 'center',
    gap: 10,
  },
  cardCode: {
    fontSize: 12,
    fontWeight: 700,
    color: INK,
    fontFamily: 'monospace',
    letterSpacing: '0.04em',
  },
  badgePendiente: {
    fontSize: 11,
    fontWeight: 700,
    color: AMBER_TXT,
    background: AMBER_BG,
    padding: '3px 9px',
    borderRadius: 20,
    letterSpacing: '0.03em',
  },
  cardDate: {
    display: 'flex',
    alignItems: 'center',
    fontSize: 12,
    color: INK_SOFT,
  },
  cardBody: {
    padding: '18px',
    flex: 1,
  },
  programaNombre: {
    fontSize: 15,
    fontWeight: 600,
    color: INK,
    margin: '0 0 16px',
    lineHeight: 1.4,
    letterSpacing: '-0.1px',
  },
  infoGrid: {
    display: 'grid',
    gridTemplateColumns: '1fr',
    gap: 10,
    marginBottom: 14,
  },
  infoItem: {
    display: 'flex',
    flexDirection: 'column',
    gap: 2,
    padding: '9px 12px',
    background: BG,
    borderRadius: 7,
    border: `1px solid ${BORDER}`,
  },
  infoLabel: {
    fontSize: 11,
    fontWeight: 600,
    color: INK_SOFT,
    textTransform: 'uppercase',
    letterSpacing: '0.06em',
  },
  infoVal: {
    fontSize: 14,
    fontWeight: 500,
    color: INK,
  },
  mensajeBox: {
    background: '#fafafa',
    border: `1px solid ${BORDER}`,
    borderRadius: 7,
    padding: '10px 12px',
  },
  mensajeLabel: {
    fontSize: 11,
    fontWeight: 600,
    color: INK_SOFT,
    textTransform: 'uppercase',
    letterSpacing: '0.06em',
    display: 'block',
    marginBottom: 4,
  },
  mensajeText: {
    fontSize: 13,
    color: INK_SOFT,
    margin: 0,
    fontStyle: 'italic',
    lineHeight: 1.5,
  },

  /* Card footer */
  cardFooter: {
    padding: '14px 18px',
    borderTop: `1px solid ${BORDER}`,
  },
  btn: {
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    width: '100%',
    background: TEAL,
    color: WHITE,
    border: 'none',
    borderRadius: 8,
    padding: '11px 20px',
    fontSize: 14,
    fontWeight: 600,
    cursor: 'pointer',
    letterSpacing: '-0.1px',
  },

  /* Modal */
  modalOverlay: {
    position: 'fixed',
    top: 0, left: 0, right: 0, bottom: 0,
    backgroundColor: 'rgba(15, 20, 30, 0.6)',
    display: 'flex',
    justifyContent: 'center',
    alignItems: 'center',
    zIndex: 1000,
  },
  modalContent: {
    maxWidth: 900,
    width: '90%',
    maxHeight: '90vh',
    overflowY: 'auto',
    borderRadius: 14,
    boxShadow: '0 24px 60px rgba(0,0,0,0.25)',
  },
};

export default SolicitudesPendientes;
